$ErrorActionPreference = "Stop"
Set-Location "C:\Users\mike.balducci\downloads\onsiteaffiliate.com"

Write-Host "`n=== Presentations Update v3 ===" -ForegroundColor Cyan
Write-Host "  - Horizontal carousel with keyboard nav" -ForegroundColor Gray
Write-Host "  - Brand logo upload in admin" -ForegroundColor Gray
Write-Host "  - Flywheel static image" -ForegroundColor Gray
Write-Host "  - Consistent phase card borders" -ForegroundColor Gray
Write-Host "  - Pricing table title" -ForegroundColor Gray

function Write-B64File {
    param([string]$Path, [string]$B64)
    $fullPath = Join-Path $PWD $Path
    $dir = Split-Path $fullPath -Parent
    if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
    [System.IO.File]::WriteAllBytes($fullPath, [System.Convert]::FromBase64String($B64))
    Write-Host "  Updated: $Path" -ForegroundColor Green
}

Write-Host "`n--- Updating source files ---" -ForegroundColor Cyan
Write-B64File "src\PresentationPage.js" ""
Write-B64File "src\AdminPage.js" ""
Write-B64File "src\usePresentations.js" ""
Write-B64File "src\presentations.css" ""
Write-B64File "supabase-schema.sql" ""

Write-Host "`n--- Database Migration ---" -ForegroundColor Cyan
Write-Host "  Run this in Supabase SQL Editor:" -ForegroundColor Yellow
Write-Host "  ALTER TABLE public.presentations ADD COLUMN IF NOT EXISTS logo_url text;" -ForegroundColor White

Write-Host "`n--- Flywheel Image ---" -ForegroundColor Cyan
$imgDir = "public\images"
if (!(Test-Path $imgDir)) { New-Item -ItemType Directory -Path $imgDir -Force | Out-Null }
$flywheelSrc = "FC-Flywheel_Static.png"
if (Test-Path $flywheelSrc) {
    Copy-Item $flywheelSrc "$imgDir\FC-Flywheel_Static.png" -Force
    Write-Host "  Copied $flywheelSrc to $imgDir\" -ForegroundColor Green
} else {
    Write-Host "  WARNING: $flywheelSrc not found in project root." -ForegroundColor Yellow
    Write-Host "  Download it and place it at: $imgDir\FC-Flywheel_Static.png" -ForegroundColor Yellow
}

Write-Host "`n=== Update complete! ===" -ForegroundColor Green
Write-Host "Next steps:" -ForegroundColor Cyan
Write-Host "  1. Run the ALTER TABLE migration in Supabase SQL Editor" -ForegroundColor White
Write-Host "  2. Place FC-Flywheel_Static.png in public\images\ (if not already)" -ForegroundColor White
Write-Host "  3. npm start to test" -ForegroundColor White
